// src/pages/BlogEdit.js
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import jwtDecode from "jwt-decode";

const BlogEdit = () => {
  const [openMaster, setOpenMaster] = useState(false);
  const [blogs, setBlogs] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({
    id: null,
    title: "",
    content: "",
    image_url: "",
    category_id: "",
  });
  const [loading, setLoading] = useState(false);

  const token = localStorage.getItem("token");
  const user = token ? jwtDecode(token) : null;

  const API_BASE = "http://localhost:5000/api";

  // Fetch blogs from backend
  const fetchBlogs = async () => {
    try {
      const res = await fetch(`${API_BASE}/blogs`);
      const data = await res.json();
      setBlogs(data);
    } catch (err) {
      console.error("Error fetching blogs:", err);
    }
  };

  // Fetch categories from backend
  const fetchCategories = async () => {
    try {
      const res = await fetch(`${API_BASE}/categories`);
      const data = await res.json();
      setCategories(data);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  useEffect(() => {
    fetchBlogs();
    fetchCategories();
  }, []);

  // Handle form input change
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Submit form for create or update
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!token) {
      alert("You must be logged in as admin to perform this action.");
      return;
    }
    if (!form.title || !form.content || !form.category_id) {
      alert("Please fill all required fields.");
      return;
    }

    setLoading(true);
    try {
      const method = form.id ? "PUT" : "POST";
      const url = form.id
        ? `${API_BASE}/blogs/${form.id}`
        : `${API_BASE}/blogs`;

      const body = {
        title: form.title,
        content: form.content,
        image_url: form.image_url,
        category_id: form.category_id,
        user_id: user?.id || 1, // fallback for testing
      };

      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(body),
      });

      if (!res.ok) {
        const errData = await res.json();
        throw new Error(errData.message || "Failed to save blog");
      }

      setForm({ id: null, title: "", content: "", image_url: "", category_id: "" });
      fetchBlogs();
    } catch (err) {
      console.error("Error saving blog:", err);
      alert(err.message);
    }
    setLoading(false);
  };

  // Edit existing blog
  const handleEdit = (blog) => {
    setForm({
      id: blog.id,
      title: blog.title,
      content: blog.content,
      image_url: blog.image_url || "",
      category_id: blog.category_id,
    });
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  // Delete blog
  const handleDelete = async (id) => {
    if (!token) {
      alert("You must be logged in as admin to perform this action.");
      return;
    }
    if (!window.confirm("Are you sure you want to delete this blog?")) return;

    try {
      const res = await fetch(`${API_BASE}/blogs/${id}`, {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      if (!res.ok) throw new Error("Failed to delete blog");
      fetchBlogs();
    } catch (err) {
      console.error("Error deleting blog:", err);
      alert(err.message);
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <div className="w-64 bg-white border-r shadow fixed left-0 top-0 h-full z-10">
        <div className="px-6 py-4 border-b">
          <img src="/your-logo.png" alt="Logo" className="w-36" />
          <p className="text-sm text-gray-500">Blog Management</p>
        </div>
        <nav className="mt-4 px-4">
          <div
            onMouseEnter={() => setOpenMaster(true)}
            onMouseLeave={() => setOpenMaster(false)}
            className="relative cursor-pointer"
          >
            <p className="py-2 font-medium text-gray-800 hover:text-blue-600 flex justify-between items-center">
              Master <span>›</span>
            </p>
            {openMaster && (
              <div className="ml-4 space-y-2">
                <Link
                  to="/admin/category-manage"
                  className="block text-sm text-gray-600 hover:text-blue-600"
                >
                  ➤ Edit Category
                </Link>
                <Link
                  to="/admin/blog-manage"
                  className="block text-sm text-gray-600 hover:text-blue-600"
                >
                  ➤ Edit Blog
                </Link>
              </div>
            )}
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <div className="ml-64 flex-1 p-6">
        <h1 className="text-2xl font-bold mb-4">
          {form.id ? "Edit Blog" : "Create Blog"}
        </h1>
        <form
          onSubmit={handleSubmit}
          className="bg-white shadow rounded p-4 mb-6"
        >
          <input
            type="text"
            name="title"
            placeholder="Title"
            value={form.title}
            onChange={handleChange}
            className="border p-2 w-full mb-3"
          />
          <textarea
            name="content"
            placeholder="Content"
            value={form.content}
            onChange={handleChange}
            className="border p-2 w-full mb-3"
          ></textarea>
          <input
            type="text"
            name="image_url"
            placeholder="Image URL"
            value={form.image_url}
            onChange={handleChange}
            className="border p-2 w-full mb-3"
          />
          <select
            name="category_id"
            value={form.category_id}
            onChange={handleChange}
            className="border p-2 w-full mb-3"
          >
            <option value="">Select Category</option>
            {categories.map((cat) => (
              <option key={cat.id} value={cat.id}>
                {cat.name}
              </option>
            ))}
          </select>
          <button
            type="submit"
            disabled={loading}
            className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
          >
            {loading ? "Saving..." : form.id ? "Update Blog" : "Create Blog"}
          </button>
        </form>

        <h2 className="text-xl font-bold mb-2">All Blogs</h2>
        <table className="w-full bg-white shadow rounded">
          <thead>
            <tr className="bg-gray-200">
              <th className="p-2 border">Title</th>
              <th className="p-2 border">Category</th>
              <th className="p-2 border">Author</th>
              <th className="p-2 border">Actions</th>
            </tr>
          </thead>
          <tbody>
            {blogs.map((blog) => (
              <tr key={blog.id}>
                <td className="p-2 border">{blog.title}</td>
                <td className="p-2 border">{blog.category_name}</td>
                <td className="p-2 border">{blog.username}</td>
                <td className="p-2 border space-x-2">
                  <button
                    onClick={() => handleEdit(blog)}
                    className="bg-yellow-500 text-white px-2 py-1 rounded"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(blog.id)}
                    className="bg-red-500 text-white px-2 py-1 rounded"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
            {blogs.length === 0 && (
              <tr>
                <td colSpan="4" className="p-4 text-center">
                  No blogs found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default BlogEdit;
